/*	설	명 : 사용자설정수정,  ASIS - UsrUserInfoDAO.updateUserConf	*/
UPDATE 	TB_LMS_USR
SET 	USER_ENV_STNG_CTS = #{userEnvStngCts}
WHERE 	USER_ID = #{userId}

mapper.select:
/*	설	명 : 사용자조회, ASIS - UsrUserInfoDAO.viewUser		*/
SELECT	*
FROM 	TB_LMS_USER USR
WHERE 	USER_ID = #{userId}

/*  설 명 : 등록된사용자들조회 - 대표아이디로등록된사용자들조회 */
SELECT	*
FROM 	TB_LMS_USER USR
WHERE 	USER_RPRS_ID = #{userRprsId}
